  /// Redact sensitive values from a map (e.g., request headers, body)
  Map<String, dynamic> _redactMap(Map<String, dynamic> data) {
    final redacted = <String, dynamic>{};
    for (final entry in data.entries) {
      final keyLower = entry.key.toLowerCase().replaceAll(RegExp(r'[-_]'), '');
      if (_sensitiveKeys
