/// Logger for HTTP requests and responses
class HttpLogger {
  static const _category = 'HTTP';
  static final _logger = SecureLogger();

  /// Log an outgoing HTTP request.
  /// Sensitive headers (Authorization, Cookie) are automatically redacted.
  static void logRequest({
    required String method,
    required String url,
    Map<String, dynamic>? headers,
    dynamic body,
  }) {
    // Parse URL to remove any query params that might contain tokens
    final uri = Uri.tryParse(url);
    final safeUrl = uri != null
        ? '${uri.scheme}://${uri.host}${uri.path}${uri.queryParameters.isNotEmpty ? '?[query_redacted]' : ''}'
        : '[invalid_url]';

    _logger.debug(_category, '$method $safeUrl', data: {
      if (headers != null) 'headers': headers,
      if (body != null && body is Map<String, dynamic>) 'body': body,
      if (body != null && body is! Map<String, dynamic>)
        'body_type': body.runtimeType.toString(),
    });
  }

  /// Log an HTTP response.
  /// Response bodies are NOT logged to prevent data leakage.
  static void logResponse({
    required String method,
    required String url,
    required int statusCode,
    int? contentLength,
    Duration? duration,
  }) {
    final uri = Uri.tryParse(url);
    final safeUrl = uri != null
        ? '${uri.scheme}://${uri.host}${uri.path}'
        : '[invalid_url]';

    final level = statusCode >= 500
        ? LogLevel.error
        : statusCode >= 400
            ? LogLevel.warning
            : LogLevel.debug;

    final data = <String, dynamic>{
      'status': statusCode,
      if (contentLength != null) 'content_length': contentLength,
      if (duration != null) 'duration_ms': duration.inMilliseconds,
    };

    switch (level) {
      case LogLevel.error:
        _logger.error(_category, '$method $safeUrl -> $statusCode', data: data);
        break;
      case LogLevel.warning:
        _logger.warning(_category, '$method $safeUrl -> $statusCode',
            data: data);
        break;
      default:
        _logger.debug(_category, '$method $safeUrl -> $statusCode', data: data);
    }
  }

  /// Log an HTTP error (network failure, timeout, etc.)
  static void logError({
    required String method,
    required String url,
    required Object error,
    StackTrace? stackTrace,
  }) {
    final uri = Uri.tryParse(url);
    final safeUrl = uri != null
        ? '${uri.scheme}://${uri.host}${uri.path}'
        : '[invalid_url]';

    _logger.error(
      _category,
      '$method $safeUrl failed',
      error: error,
      stackTrace: stackTrace,
    );
  }
}

/// Logger for database operations
class DatabaseLogger {
  static const _category = 'DATABASE';
  static final _logger = SecureLogger();

  /// Log a database query. Parameter values are NOT logged.
  static void logQuery({
    required String operation,
    required String table,
    int? rowCount,
    Duration? duration,
  }) {
    _logger.debug(_category, '$operation on $table', data: {
      if (rowCount != null) 'row_count': rowCount,
      if (duration != null) 'duration_ms': duration.inMilliseconds,
    });
  }

  /// Log a database error
  static void logError({
    required String operation,
    required String table,
    required Object error,
    StackTrace? stackTrace,
  }) {
    // Do NOT include the query or parameters - they may contain user data
    _logger.error(
      _category,
      '$operation on $table failed',
      error: error,
      stackTrace: stackTrace,
    );
  }

  /// Log a migration event
  static void logMigration({
    required int fromVersion,
    required int toVersion,
    required bool success,
    Duration? duration,
  }) {
    if (success) {
      _logger.info(_category, 'Migration $fromVersion -> $toVersion succeeded',
          data: {
            if (duration != null) 'duration_ms': duration.inMilliseconds,
          });
    } else {
      _logger.error(
          _category, 'Migration $fromVersion -> $toVersion failed');
    }
  }
}

/// Logger for authentication flows.
/// CRITICAL: Never log credentials, tokens, or session identifiers.
class AuthLogger {
  static const _category = 'AUTH';
  static final _logger = SecureLogger();

  /// Log an authentication attempt. Only log the outcome, never credentials.
  static void logLoginAttempt({
    required bool success,
    required String method, // e.g., 'email', 'google', 'biometric'
    String? failureReason, // e.g., 'invalid_credentials', 'account_locked'
  }) {
    if (success) {
      _logger.info(_category, 'Login succeeded via $method');
    } else {
      // Log failure reason but NEVER the actual credentials
      _logger.warning(_category, 'Login failed via $method', data: {
        if (failureReason != null) 'reason': failureReason,
      });
    }
  }

  /// Log a logout event
  static void logLogout({required String reason}) {
    _logger.info(_category, 'User logged out', data: {'reason': reason});
  }

  /// Log a token refresh (without logging the token itself)
  static void logTokenRefresh({required bool success, String? errorReason}) {
    if (success) {
      _logger.debug(_category, 'Token refresh succeeded');
    } else {
      _logger.warning(_category, 'Token refresh failed', data: {
        if (errorReason != null) 'reason': errorReason,
      });
    }
  }

  /// Log a password reset request (without logging the email)
  static void logPasswordResetRequest({required bool success}) {
    _logger.info(_category,
        'Password reset ${success ? "requested" : "request failed"}');
  }

  /// Log MFA events
  static void logMfaEvent({
    required String event, // e.g., 'challenge_sent', 'verified', 'failed'
    required String method, // e.g., 'sms', 'totp', 'email'
  }) {
    _logger.info(_category, 'MFA $event via $method');
  }
}

/// Logger for user interactions (analytics-safe)
class InteractionLogger {
  static const _category = 'UI';
  static final _logger = SecureLogger();

  /// Log a screen view
  static void logScreenView({required String screenName}) {
    _logger.debug(_category, 'Screen viewed: $screenName');
  }

  /// Log a user action (button tap, form submission, etc.)
  /// Never log the actual data the user entered.
  static void logAction({
    required String action,
    required String target,
    Map<String, dynamic>? metadata,
  }) {
    _logger.debug(_category, '$action on $target', data: metadata);
  }

  /// Log an error shown to the user
  static void logUserError({
    required String screenName,
    required String errorType,
  }) {
    _logger.info(_category, 'Error shown on $screenName: $errorType');
  }
}

