void exampleUsage() {
  final logger = SecureLogger();

  // ✅ CORRECT: Log the operation outcome, not the data
  logger.info('PAYMENT', 'Payment processed successfully', data: {
    'amount': 29.99,
    'currency': 'USD',
    // card_number will be automatically redacted
    'card_number': '4111-1111-1111-1111',
  });

  // ✅ CORRECT: HTTP logging with automatic redaction
  HttpLogger.logRequest(
    method: 'POST',
    url: 'https://api.example.com/auth/login',
    headers: {
      'Content-Type': 'application/json',
      'Authorization': 'Bearer eyJhbGciOiJIUzI1NiJ9.test.sig',
    },
    body: {
      'username': 'user@example.com',
      'password': 'supersecret123', // Will be redacted
    },
  );

  // ✅ CORRECT: Auth logging without credentials
  AuthLogger.logLoginAttempt(
    success: false,
    method: 'email',
    failureReason: 'invalid_credentials',
  );

  // ✅ CORRECT: Database logging without query parameters
  DatabaseLogger.logQuery(
    operation: 'SELECT',
    table: 'users',
    rowCount: 1,
    duration: const Duration(milliseconds: 12),
  );

  // ❌ NEVER DO THIS (the SecureLogger prevents it, but don't even try):
  // print('User password: $password');
  // debugPrint('Token: $accessToken');
  // print('Full request: ${jsonEncode(requestWithSecrets)}');
}